class Sam3LiteTextLayerNormFP32(nn.LayerNorm):
    """LayerNorm that casts input to float32 for numerical stability."""

    def forward(self, input: torch.Tensor) -> torch.Tensor:
        input_dtype = input.dtype
        return super().forward(input.to(torch.float32)).to(input_dtype)


class Sam3LiteTextLearnablePositionalEmbedding(nn.Module):
    """Learnable positional embeddings with interpolation support for variable sequence lengths."""

    def __init__(self, num_embeddings: int, embedding_dim: int):
        super().__init__()
        self.pos_embed = nn.Parameter(torch.empty(1, 1, num_embeddings, embedding_dim))
        self.embedding_dim = embedding_dim
        self.num_embeddings = num_embeddings

    def forward(self, seq_len: int) -> torch.Tensor:
        pos_embed = self.pos_embed
        if seq_len != self.num_embeddings:
            pos_embed = F.interpolate(
                pos_embed,
                size=(seq_len, self.embedding_dim),
                mode="bilinear",
                align_corners=False,
            )
        return pos_embed.reshape(1, seq_len, self.embedding_dim)


class Sam3LiteTextMobileOneBlock(nn.Module):
    """
    Reparameterizable convolution block with multi-branch training that fuses
    to a single convolution at inference.

    During training, uses parallel branches (conv+BN, scale+BN, skip+BN).
    At inference, all branches are fused into one convolution via `reparameterize()`.
    """

    def __init__(
        self,
        in_channels: int,
        out_channels: int,
        kernel_size: int | tuple[int, int],
        stride: int = 1,
        padding: int | tuple[int, int] = 0,
        groups: int = 1,
        use_act: bool = True,
        use_scale_branch: bool = True,
        num_conv_branches: int = 1,
    ):
        super().__init__()
        self.groups = groups
        self.stride = stride
        self.padding = padding
        self.kernel_size = kernel_size
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.num_conv_branches = num_conv_branches
        self.activation = nn.GELU() if use_act else nn.Identity()

        # Skip (identity) branch: only when dimensions match
        self.rbr_skip = (
            nn.BatchNorm2d(num_features=in_channels) if out_channels == in_channels and stride == 1 else None
        )

        # Convolution branches
        if num_conv_branches > 0:
            self.rbr_conv = nn.ModuleList(
                [self._conv_bn(kernel_size=kernel_size, padding=padding) for _ in range(num_conv_branches)]
            )
        else:
            self.rbr_conv = None

        # Scale (1x1) branch
        self.rbr_scale = None
        ks = kernel_size if isinstance(kernel_size, int) else kernel_size[0]
        if ks > 1 and use_scale_branch:
            self.rbr_scale = self._conv_bn(kernel_size=1, padding=0)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        identity_out = 0
        if self.rbr_skip is not None:
            identity_out = self.rbr_skip(x)

        scale_out = 0
        if self.rbr_scale is not None:
            scale_out = self.rbr_scale(x)

        out = scale_out + identity_out
        if self.rbr_conv is not None:
            for conv_branch in self.rbr_conv:
                out = out + conv_branch(x)

        return self.activation(out)

    def reparameterize(self):
        """Fuse all branches into a single convolution for inference."""
        kernel, bias = self._get_kernel_bias()
        self.reparam_conv = nn.Conv2d(
            in_channels=self.in_channels,
            out_channels=self.out_channels,
            kernel_size=self.kernel_size,
            stride=self.stride,
            padding=self.padding,
            groups=self.groups,
            bias=True,
        )
        self.reparam_conv.weight.data = kernel
        self.reparam_conv.bias.data = bias

        for para in self.parameters():
            para.detach_()
        if hasattr(self, "rbr_conv"):
            del self.rbr_conv
            self.rbr_conv = None
        if hasattr(self, "rbr_scale"):
            del self.rbr_scale
            self.rbr_scale = None
        if hasattr(self, "rbr_skip"):
            del self.rbr_skip
            self.rbr_skip = None

    def _get_kernel_bias(self):
        kernel_scale, bias_scale = 0, 0
        if self.rbr_scale is not None:
            kernel_scale, bias_scale = self._fuse_bn_tensor(self.rbr_scale)
            ks = self.kernel_size if isinstance(self.kernel_size, int) else self.kernel_size[1]
            pad = ks // 2
            kernel_scale = F.pad(kernel_scale, [pad, pad, pad, pad])

        kernel_identity, bias_identity = 0, 0
        if self.rbr_skip is not None:
            kernel_identity, bias_identity = self._fuse_bn_tensor(self.rbr_skip)

        kernel_conv, bias_conv = 0, 0
        if self.rbr_conv is not None:
            for conv_branch in self.rbr_conv:
                k, b = self._fuse_bn_tensor(conv_branch)
                kernel_conv = kernel_conv + k
                bias_conv = bias_conv + b

        return kernel_conv + kernel_scale + kernel_identity, bias_conv + bias_scale + bias_identity

    def _fuse_bn_tensor(self, branch: nn.Sequential | nn.BatchNorm2d) -> tuple[torch.Tensor, torch.Tensor]:
        if isinstance(branch, nn.Sequential):
            kernel = branch.conv.weight
            bn = branch.bn
        else:
            # BatchNorm identity branch
            if not hasattr(self, "id_tensor"):
                input_dim = self.in_channels // self.groups
                kernel_size = self.kernel_size
                if isinstance(kernel_size, int):
                    kernel_size = (kernel_size, kernel_size)
                kernel_value = torch.zeros(
                    (self.in_channels, input_dim, kernel_size[0], kernel_size[1]),
                    dtype=branch.weight.dtype,
                    device=branch.weight.device,
                )
                for i in range(self.in_channels):
                    kernel_value[i, i % input_dim, kernel_size[0] // 2, kernel_size[1] // 2] = 1
                self.id_tensor = kernel_value
            kernel = self.id_tensor
            bn = branch
        std = (bn.running_var + bn.eps).sqrt()
        t = (bn.weight / std).reshape(-1, 1, 1, 1)
        return kernel * t, bn.bias - bn.running_mean * bn.weight / std

    def _conv_bn(self, kernel_size, padding):
        mod = nn.Sequential()
        mod.add_module(
            "conv",
            nn.Conv2d(
                in_channels=self.in_channels,
                out_channels=self.out_channels,
                kernel_size=kernel_size,
                stride=self.stride,
                padding=padding,
                groups=self.groups,
                bias=False,
            ),
        )
        mod.add_module("bn", nn.BatchNorm2d(num_features=self.out_channels))
        return mod


class Sam3LiteTextRepMixer(nn.Module):
    """
    Token mixing via reparameterizable depthwise convolution.

    During training: computes `x + layer_scale * (mixer(x) - norm(x))`.
    After reparameterization: a single depthwise convolution.
    """

    def __init__(self, dim: int, kernel_size: int = 3, layer_scale_init_value: float = 1e-5):
        super().__init__()
        self.dim = dim
        self.kernel_size = kernel_size

        self.norm = Sam3LiteTextMobileOneBlock(
            dim,
            dim,
            (1, kernel_size),
            padding=(0, kernel_size // 2),
            groups=dim,
            use_act=False,
            use_scale_branch=False,
            num_conv_branches=0,
        )
        self.mixer = Sam3LiteTextMobileOneBlock(
            dim,
            dim,
            (1, kernel_size),
            padding=(0, kernel_size // 2),
            groups=dim,
            use_act=False,
        )
        self.layer_scale = nn.Parameter(layer_scale_init_value * torch.ones((dim, 1, 1)), requires_grad=True)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        if hasattr(self, "reparam_conv"):
            return self.reparam_conv(x)
        return x + self.layer_scale * (self.mixer(x) - self.norm(x))

    def reparameterize(self):
        """Fuse mixer, norm, and layer_scale into a single depthwise convolution."""
        self.mixer.reparameterize()
        self.norm.reparameterize()

        w = self.mixer.id_tensor + self.layer_scale.unsqueeze(-1) * (
            self.mixer.reparam_conv.weight - self.norm.reparam_conv.weight
        )
        b = torch.squeeze(self.layer_scale) * (self.mixer.reparam_conv.bias - self.norm.reparam_conv.bias)

        self.reparam_conv = nn.Conv2d(
            in_channels=self.dim,
            out_channels=self.dim,
            kernel_size=(1, self.kernel_size),
            stride=1,
            padding=(0, self.kernel_size // 2),
            groups=self.dim,
            bias=True,
        )
        self.reparam_conv.weight.data = w
        self.reparam_conv.bias.data = b

        for para in self.parameters():
            para.detach_()
        del self.mixer
        del self.norm
        del self.layer_scale


class Sam3LiteTextConvFFN(nn.Module):
    """Conv-based feed-forward network: depthwise conv + two pointwise convolutions."""

    def __init__(self, in_channels: int, context_size: int, hidden_channels: int, dropout: float = 0.0):
        super().__init__()
        self.conv = nn.Sequential()
        self.conv.add_module(
            "conv",
            nn.Conv2d(
                in_channels=in_channels,
                out_channels=in_channels,
                kernel_size=(1, context_size),
                padding=(0, context_size // 2),
                groups=in_channels,
                bias=False,
            ),
        )
        self.conv.add_module("bn", nn.BatchNorm2d(num_features=in_channels))
        self.fc1 = nn.Conv2d(in_channels, hidden_channels, kernel_size=1)
        self.act = nn.GELU()
        self.fc2 = nn.Conv2d(hidden_channels, in_channels, kernel_size=1)
        self.drop = nn.Dropout(dropout)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        x = self.conv(x)
        x = self.fc1(x)
        x = self.act(x)
        x = self.drop(x)
        x = self.fc2(x)
        x = self.drop(x)
        return x


class Sam3LiteTextRepMixerBlock(GradientCheckpointingLayer):
    """
    RepMixer block: token mixing via RepMixer + ConvFFN.

    Input shape: (batch, seq_len, dim) -> reshapes to (batch, dim, 1, seq_len) for conv ops.
    """

    def __init__(self, config: Sam3LiteTextMobileCLIPConfig):
        super().__init__()
        dim = config.hidden_size
        kernel_size = config.kernel_size
        mlp_hidden_dim = config.intermediate_size

        self.token_mixer = Sam3LiteTextRepMixer(
            dim,
            kernel_size=kernel_size,
            layer_scale_init_value=config.layer_scale_init_value,
        )
        self.convffn = Sam3LiteTextConvFFN(
            in_channels=dim,
            context_size=kernel_size,
            hidden_channels=mlp_hidden_dim,
        )
        self.layer_scale = nn.Parameter(config.layer_scale_init_value * torch.ones((dim, 1, 1)), requires_grad=True)

    def forward(self, x: torch.Tensor, **kwargs) -> torch.Tensor:
        # (B, seq, dim) -> (B, dim, 1, seq) for conv operations
        x = x.permute(0, 2, 1).unsqueeze(2)
        x = self.token_mixer(x)
        x = x + self.layer_scale * self.convffn(x)
        # (B, dim, 1, seq) -> (B, seq, dim)
        return x.squeeze(2).permute(0, 2, 1)


class Sam3LiteTextAttention(nn.Module):
    """Multi-head self-attention with fused QKV projection."""

    def __init__(self, config: Sam3LiteTextMobileCLIPConfig):
        super().__init__()
        self.num_heads = config.num_attention_heads
        self.head_dim = config.hidden_size // config.num_attention_heads
        self.scaling = self.head_dim**-0.5
        self.qkv_proj = nn.Linear(config.hidden_size, 3 * config.hidden_size)
        self.out_proj = nn.Linear(config.hidden_size, config.hidden_size)
        self.attn_dropout = nn.Dropout(config.attention_dropout)

    def forward(
        self,
        hidden_states: torch.Tensor,
        key_padding_mask: torch.Tensor | None = None,
        attn_mask: torch.Tensor | None = None,
    ) -> torch.Tensor:
        batch_size, seq_len, _ = hidden_states.shape

        qkv = self.qkv_proj(hidden_states).reshape(batch_size, seq_len, 3, self.num_heads, self.head_dim)
        qkv = qkv.permute(2, 0, 3, 1, 4)  # (3, B, heads, seq, head_dim)
        query, key, value = qkv.unbind(0)

        query = query * self.scaling
        attn_weights = torch.matmul(query, key.transpose(-1, -2))

        if attn_mask is not None:
            attn_weights = attn_weights + attn_mask.unsqueeze(1)

        if key_padding_mask is not None:
            attn_weights = attn_weights.masked_fill(
                key_padding_mask.unsqueeze(1).unsqueeze(2).to(torch.bool),
                float("-inf"),
            )

        attn_weights = F.softmax(attn_weights.float(), dim=-1).to(hidden_states.dtype)
        attn_weights = self.attn_dropout(attn_weights)
        attn_output = torch.matmul(attn_weights, value)
        attn_output = attn_output.transpose(1, 2).reshape(batch_size, seq_len, -1)
        return self.out_proj(attn_output)


class Sam3LiteTextTransformerLayer(GradientCheckpointingLayer):
    """Pre-norm transformer encoder layer with multi-head attention and FFN."""

    def __init__(self, config: Sam3LiteTextMobileCLIPConfig):
        super().__init__()
        norm_cls = Sam3LiteTextLayerNormFP32 if config.norm_type == "layer_norm_fp32" else nn.LayerNorm

        self.attn_norm = norm_cls(config.hidden_size, eps=config.layer_norm_eps)
        self.attention = Sam3LiteTextAttention(config)
        self.attn_dropout = nn.Dropout(config.hidden_dropout)

        self.ffn_norm = norm_cls(config.hidden_size, eps=config.layer_norm_eps)
        self.fc1 = nn.Linear(config.hidden_size, config.intermediate_size)
        self.act = nn.GELU()
        self.ffn_dropout = nn.Dropout(config.hidden_dropout)
        self.fc2 = nn.Linear(config.intermediate_size, config.hidden_size)
        self.output_dropout = nn.Dropout(config.hidden_dropout)

    def forward(
        self,
        hidden_states: torch.Tensor,
        key_padding_mask: torch.Tensor | None = None,
        attn_mask: torch.Tensor | None = None,
        **kwargs,
    ) -> torch.Tensor:
        # Pre-norm MHA
        residual = hidden_states
        hidden_states = self.attn_norm(hidden_states)
        hidden_states = self.attention(hidden_states, key_padding_mask=key_padding_mask, attn_mask=attn_mask)
        hidden_states = self.attn_dropout(hidden_states)
        hidden_states = residual + hidden_states

        # Pre-norm FFN
        residual = hidden_states
        hidden_states = self.ffn_norm(hidden_states)
        hidden_states = self.fc1(hidden_states)
        hidden_states = self.act(hidden_states)
        hidden_states = self.ffn_dropout(hidden_states)
        hidden_states = self.fc2(hidden_states)
        hidden_states = self.output_dropout(hidden_states)
        hidden_states = residual + hidden_states

        return hidden_states


class Sam3LiteTextMobileCLIPEncoder(PreTrainedModel):
    """
    MobileCLIP-S0 text encoder with RepMixer blocks.

    Architecture: [RepMixerBlock] + N x TransformerLayer + [RepMixerBlock]

    This replaces CLIPTextModelWithProjection in Sam3Model. It accepts `input_ids`
    and `attention_mask` and returns `BaseModelOutputWithPooling` with `last_hidden_state`.
    """

    config_class = Sam3LiteTextMobileCLIPConfig

    def _init_weights(self, module):
        """Initialize MobileCLIP-specific parameters."""
        super()._init_weights(module)
        if isinstance(module, Sam3LiteTextLearnablePositionalEmbedding):
            nn.init.trunc_normal_(module.pos_embed, mean=0, std=module.embedding_dim**-0.5)
        if isinstance(module, (Sam3LiteTextRepMixer, Sam3LiteTextRepMixerBlock)):
            nn.init.constant_(module.layer_scale, 1e-5)

    def __init__(self, config: Sam3LiteTextMobileCLIPConfig):
        super().__init__(config)
        self.config = config

        self.embedding_layer = nn.Embedding(config.vocab_size, config.hidden_size)
        self.embed_scale = config.hidden_size**-0.5

        self.positional_embedding = Sam3LiteTextLearnablePositionalEmbedding(
            num_embeddings=config.context_length,
            embedding_dim=config.hidden_size,
        )
        self.embedding_dropout = nn.Dropout(config.hidden_dropout)

        # MobileCLIP-S0 ("mct" variant): RepMixerBlock + N TransformerLayers + RepMixerBlock
        self.layers = nn.ModuleList()
        self.layers.append(Sam3LiteTextRepMixerBlock(config))
        for _ in range(config.num_hidden_layers):
            self.layers.append(Sam3LiteTextTransformerLayer(config))
        self.layers.append(Sam3LiteTextRepMixerBlock(config))

        norm_cls = Sam3LiteTextLayerNormFP32 if config.norm_type == "layer_norm_fp32" else nn.LayerNorm
        self.final_layer_norm = norm_cls(config.hidden_size, eps=config.layer_norm_eps)

        self.post_init()

    def resize_positional_embeddings(self, new_length: int):
        """Resize positional embeddings to a new context length (e.g., after loading checkpoint)."""
        pos_embed = self.positional_embedding.pos_embed
        current_length = pos_embed.shape[2]
        if new_length == current_length:
            return
        new_pos_embed = pos_embed[:, :, :new_length, :].clone()
        self.positional_embedding.pos_embed = nn.Parameter(new_pos_embed)
        self.positional_embedding.num_embeddings = new_length

    def forward(
        self,
        input_ids: torch.LongTensor,
        attention_mask: torch.Tensor | None = None,
        **kwargs,
    ) -> BaseModelOutputWithPooling:
        # Embed tokens
        hidden_states = self.embedding_layer(input_ids) * self.embed_scale
        seq_len = hidden_states.shape[1]
        hidden_states = hidden_states + self.positional_embedding(seq_len).to(hidden_states.dtype)
        hidden_states = self.embedding_dropout(hidden_states)

        # Build key padding mask from attention_mask: True = padding (to mask out)
        key_padding_mask = None
        if attention_mask is not None:
            key_padding_mask = ~attention_mask.bool()

        # Forward through layers
        for layer in self.layers:
            hidden_states = layer(hidden_states, key_padding_mask=key_padding_mask)

        hidden_states = self.final_layer_norm(hidden_states)

        return BaseModelOutputWithPooling(
            last_hidden_state=hidden_states,
            pooler_output=None,
        )


class Sam3LiteTextViTRotaryEmbedding(nn.Module):
    """
    Vision Rotary Position Embedding for SAM3_LITE_TEXT, following transformers library standards.
    Supports 2D (axial) rotary embeddings for spatial dimensions.
    """

    def __init__(self, config: Sam3LiteTextViTConfig, end_x: int, end_y: int, scale: float = 1.0):
        super().__init__()
        dim = config.hidden_size // config.num_attention_heads
        # Ensure even dimension for proper axial splitting
        if dim % 4 != 0:
            raise ValueError("Dimension must be divisible by 4 for axial RoPE")
        self.end_x, self.end_y = end_x, end_y
        self.dim = dim
        self.rope_theta = config.rope_theta
        self.scale = scale
        freqs = 1.0 / (config.rope_theta ** (torch.arange(0, dim, 4)[: (dim // 4)].float() / dim))

        flattened_indices = torch.arange(end_x * end_y, dtype=torch.long)
        x_positions = (flattened_indices % end_x) * scale
        y_positions = torch.div(flattened_indices, end_x, rounding_mode="floor") * scale
        freqs_x = torch.outer(x_positions, freqs).float()
        freqs_y = torch.outer(y_positions, freqs).float()
        inv_freq = torch.cat([freqs_x, freqs_y], dim=-1)
        inv_freq = inv_freq.repeat_interleave(2, dim=-1)
        # directly register the cos and sin embeddings as we have a fixed feature shape
        self.register_buffer("rope_embeddings_cos", inv_freq.cos(), persistent=False)
        self.register_buffer("rope_embeddings_sin", inv_freq.sin(), persistent=False)

    @torch.no_grad()
    def forward(self) -> tuple[torch.Tensor, torch.Tensor]:
        # As the feature map size is fixed for each stage, we can just return the pre-computed embeddings.
        return self.rope_embeddings_cos, self.rope_embeddings_sin


class Sam3LiteTextViTPatchEmbeddings(nn.Module):
    """
    This class turns `pixel_values` of shape `(batch_size, num_channels, height, width)` into the initial
    `hidden_states` (patch embeddings) of shape `(batch_size, seq_length, hidden_size)` to be consumed by a
    Transformer.
    """

    def __init__(self, config: Sam3LiteTextViTConfig):
        super().__init__()
        image_size, patch_size = config.pretrain_image_size, config.patch_size
        num_channels, hidden_size = config.num_channels, config.hidden_size

        image_size = image_size if isinstance(image_size, Iterable) else (image_size, image_size)
        patch_size = patch_size if isinstance(patch_size, Iterable) else (patch_size, patch_size)
        num_patches = (image_size[1] // patch_size[1]) * (image_size[0] // patch_size[0])
        self.image_size = image_size
        self.patch_size = patch_size
        self.num_channels = num_channels
        self.num_patches = num_patches

        self.projection = nn.Conv2d(num_channels, hidden_size, kernel_size=patch_size, stride=patch_size, bias=False)

    def forward(self, pixel_values: torch.Tensor) -> torch.Tensor:
        embeddings = self.projection(pixel_values.to(self.projection.weight.dtype)).flatten(2).transpose(1, 2)
        return embeddings


class Sam3LiteTextViTEmbeddings(nn.Module):
    """
    Construct the patch embeddings and position embeddings for SAM3_LITE_TEXT ViT.

    Position embeddings are tiled (not interpolated) when resizing to match different input sizes.
    """

    def __init__(self, config: Sam3LiteTextViTConfig):
        super().__init__()

        self.patch_embeddings = Sam3LiteTextViTPatchEmbeddings(config)
        num_patches = self.patch_embeddings.num_patches
        self.position_embeddings = nn.Parameter(
            torch.randn(1, num_patches, config.hidden_size)
        )  # !Remove cls token in convert weights!

        self.dropout = nn.Dropout(config.hidden_dropout)
        self.patch_size = config.patch_size

    def _tile_position_embeddings(
        self,
        position_embeddings: torch.Tensor,
        height: int,
        width: int,
    ) -> torch.Tensor:
        """
        Tile position embeddings to match target spatial dimensions.
        Args:
            position_embeddings: Shape [1, num_pretrain_patches, hidden_size]
            height: Target height in patches
            width: Target width in patches

        Returns:
            Shape [1, height * width, hidden_size]
        """
        pretrain_size = int(position_embeddings.shape[1] ** 0.5)

        # Skip tiling if sizes match (but always tile during tracing for consistent graph)
        if not torch.jit.is_tracing() and pretrain_size == height and pretrain_size == width:
            return position_embeddings.reshape(1, height * width, -1)

        # Tile position embeddings to match target spatial dimensions
        hidden_size = position_embeddings.shape[-1]
        pos_embed = position_embeddings.reshape(1, pretrain_size, pretrain_size, hidden_size).permute(0, 3, 1, 2)
        repeat_h = height // pretrain_size + 1
        repeat_w = width // pretrain_size + 1
        pos_embed = pos_embed.tile([1, 1, repeat_h, repeat_w])[:, :, :height, :width]
        return pos_embed.permute(0, 2, 3, 1).reshape(1, height * width, hidden_size)

    def forward(
        self,
        pixel_values: torch.Tensor,
        interpolate_pos_encoding: bool = False,
    ) -> torch.Tensor:
        height, width = pixel_values.shape[-2:]
        embeddings = self.patch_embeddings(pixel_values)

        # Calculate spatial dimensions in patches
        height_patches = height // self.patch_size
        width_patches = width // self.patch_size

        position_embeddings = self._tile_position_embeddings(
            self.position_embeddings,
            height_patches,
            width_patches,
        )
        embeddings = embeddings + position_embeddings
        embeddings = self.dropout(embeddings)

        return embeddings


@auto_docstring
@requires(backends=("torch", "torchvision"))
class Sam3LiteTextPreTrainedModel(PreTrainedModel):
    config_class = Sam3LiteTextConfig
    base_model_prefix = "sam3_lite_text"
    main_input_name = "pixel_values"
    input_modalities = ["image", "text"]
    _supports_sdpa = True
    _supports_flash_attn = True
    _supports_flex_attn = True
    _supports_attention_backend = True

    def _init_weights(self, module):
        """Handle MobileCLIP-specific parameters, delegate the rest to parent."""
        super()._init_weights(module)
        if isinstance(module, Sam3LiteTextViTEmbeddings):
            init.normal_(module.position_embeddings, mean=0.0, std=self.config.initializer_range)
        elif isinstance(module, Sam3LiteTextViTRotaryEmbedding):
            end_x, end_y = module.end_x, module.end_y
            dim = module.dim
            freqs = 1.0 / (module.rope_theta ** (torch.arange(0, dim, 4)[: (dim // 4)].float() / dim))
            flattened_indices = torch.arange(end_x * end_y, dtype=torch.long)
            x_positions = (flattened_indices % end_x) * module.scale
            y_positions = torch.div(flattened_indices, end_x, rounding_mode="floor") * module.scale
            freqs_x = torch.outer(x_positions, freqs).float()
            freqs_y = torch.outer(y_positions, freqs).float()
            inv_freq = torch.cat([freqs_x, freqs_y], dim=-1)
            inv_freq = inv_freq.repeat_interleave(2, dim=-1)
            init.copy_(module.rope_embeddings_cos, inv_freq.cos())
            init.copy_(module.rope_embeddings_sin, inv_freq.sin())
        if isinstance(module, Sam3LiteTextLearnablePositionalEmbedding):
            nn.init.trunc_normal_(module.pos_embed, mean=0, std=module.embedding_dim**-0.5)
        if isinstance(module, (Sam3LiteTextRepMixer, Sam3LiteTextRepMixerBlock)):
            nn.init.constant_(module.layer_scale, 1e-5)


class Sam3LiteTextMLP(nn.Module):
    def __init__(self, config: Sam3LiteTextViTConfig):
        super().__init__()
        self.config = config
        self.activation_fn = ACT2FN[config.hidden_act]
        self.fc1 = nn.Linear(config.hidden_size, config.intermediate_size)
        self.fc2 = nn.Linear(config.intermediate_size, config.hidden_size)
        self.dropout = nn.Dropout(config.hidden_dropout)

    def forward(self, hidden_states: torch.Tensor) -> torch.Tensor:
        hidden_states = self.fc1(hidden_states)
        hidden_states = self.dropout(hidden_states)
        hidden_states = self.activation_fn(hidden_states)
        hidden_states = self.fc2(hidden_states)
        return hidden_states


def eager_attention_forward(
    module: nn.Module,
    query: torch.Tensor,
    key: torch.Tensor,
    value: torch.Tensor,
    attention_mask: torch.Tensor | None,
    scaling: float | None = None,
    dropout: float = 0.0,
    **kwargs: Unpack[TransformersKwargs],
):
    if scaling is None:
        scaling = query.size(-1) ** -0.5

    # Take the dot product between "query" and "key" to get the raw attention scores.
    attn_weights = torch.matmul(query, key.transpose(2, 3)) * scaling

    if attention_mask is not None:
        attn_weights = attn_weights + attention_mask

    attn_weights = nn.functional.softmax(attn_weights, dim=-1)
    attn_weights = nn.functional.dropout(attn_weights, p=dropout, training=module.training)

    attn_output = torch.matmul(attn_weights, value)
    attn_output = attn_output.transpose(1, 2).contiguous()

    return attn_output, attn_weights


def rotate_pairwise(x):
    """
    pairwise rotation of the hidden dims of the input. Differerent from Llama Half-Tensor Rotation.

    This is an optimized version of the following more explicit implementation:
    ```python
    x_rotated = torch.zeros_like(x, dtype=x.dtype, device=x.device)
    x_rotated[..., ::2] = -x[..., 1::2]
    x_rotated[..., 1::2] = x[..., ::2]
    return x_rotated
    ```
    """
    x = x.view(*x.shape[:-1], -1, 2)
    x1, x2 = x.unbind(dim=-1)
    x = torch.stack((-x2, x1), dim=-1)
    return x.flatten(start_dim=-2)


def apply_rotary_pos_emb_2d(
    q: torch.Tensor,
    k: torch.Tensor,
    cos: torch.Tensor,
    sin: torch.Tensor,
) -> tuple[torch.Tensor, torch.Tensor]:
    """
    Apply rotary position embedding to query and key tensors for self-attention.

    Args:
        q: Query tensor of shape (batch_size, num_windows, seq_len, num_heads, head_dim)
        k: Key tensor of shape (batch_size, num_windows, seq_len, num_heads, head_dim)
        cos: Cosine position embedding of shape (seq_len, head_dim)
        sin: Sine position embedding of shape (seq_len, head_dim)

    Returns:
        Rotated (q, k) tensors
    """
    q_embed = q.float()
    q_embed = (q_embed * cos) + (rotate_pairwise(q_embed) * sin)

    k_embed = k.float()
    k_embed = (k_embed * cos) + (rotate_pairwise(k_embed) * sin)

    return q_embed.type_as(q), k_embed.type_as(k)


class Sam3LiteTextViTRoPEAttention(nn.Module):
    """Self-attention with rotary position encoding."""

    def __init__(self, config: Sam3LiteTextViTConfig):
        super().__init__()
        self.config = config
        self.hidden_size = config.hidden_size
        self.num_attention_heads = config.num_attention_heads
        self.head_dim = self.hidden_size // config.num_attention_heads
        self.scaling = self.head_dim**-0.5
        self.attention_dropout = config.attention_dropout
        self.is_causal = False

        self.q_proj = nn.Linear(self.hidden_size, self.hidden_size)
        self.k_proj = nn.Linear(self.hidden_size, self.hidden_size)
        self.v_proj = nn.Linear(self.hidden_size, self.hidden_size)
        self.o_proj = nn.Linear(self.hidden_size, self.hidden_size)

    def forward(
        self,
        hidden_states: torch.Tensor,
        position_embeddings: tuple[torch.Tensor, torch.Tensor],
        **kwargs: Unpack[TransformersKwargs],
    ) -> Tensor:
        batch_size, height, width, _ = hidden_states.shape
        seq_len = height * width
        new_shape = (batch_size, seq_len, self.num_attention_heads, self.head_dim)
        query = self.q_proj(hidden_states).view(*new_shape).transpose(1, 2)
        key = self.k_proj(hidden_states).view(*new_shape).transpose(1, 2)
        value = self.v_proj(hidden_states).view(*new_shape).transpose(1, 2)
        cos, sin = position_embeddings
        query, key = apply_rotary_pos_emb_2d(query, key, cos=cos, sin=sin)

        attention_interface: Callable = ALL_ATTENTION_FUNCTIONS.get_interface(
            self.config._attn_implementation, eager_attention_forward
        )

        attn_output, attn_weights = attention_interface(
            self,
            query,
            key,
            value,
            attention_mask=None,
            dropout=0.0 if not self.training else self.attention_dropout,
            scaling=self.scaling,
            is_causal=self.is_causal,
            **kwargs,
        )
        attn_output = attn_output.reshape(batch_size, height, width, -1).contiguous()
        attn_output = self.o_proj(attn_output)
        return attn_output, attn_weights


def window_partition(hidden_state, window_size):
    """
    Partition into non-overlapping windows with padding if needed.

    Args:
        hidden_state (`torch.Tensor`):
            Input tokens with [batch_size, height, width, num_channels].
        window_size (`int`):
            Window size.

    Returns:
        `tuple(torch.FloatTensor)` comprising various elements:
        - windows: windows after partition with [batch_size * num_windows, window_size, window_size, num_channels].
        - (padded_height, padded_width): padded height and width before partition
    """
    batch_size, height, width, num_channels = hidden_state.shape
    pad_height = (window_size - height % window_size) % window_size
    pad_width = (window_size - width % window_size) % window_size

    # Noop in case pad_width == 0 and pad_height == 0.
    hidden_state = nn.functional.pad(hidden_state, (0, 0, 0, pad_width, 0, pad_height))

    padded_height, padded_width = height + pad_height, width + pad_width

    hidden_state = hidden_state.view(
        batch_size, padded_height // window_size, window_size, padded_width // window_size, window_size, num_channels
    )
    windows = hidden_state.permute(0, 1, 3, 2, 4, 5).contiguous().view(-1, window_size, window_size, num_channels)
    return windows, (padded_height, padded_width)


def window_unpartition(windows, window_size, pad_height_width, height_width):
    """
    Window unpartition into original sequences and removing padding.

    Args:
        windows (`torch.Tensor`):
            Input tokens with [batch_size * num_windows, window_size, window_size, num_channels].
        window_size (`int`):
            Window size.
        pad_height_width (`tuple[int]`):
            Padded height and width (padded_height, padded_width).
        height_width (`tuple[int]`):
            Original height and width before padding.

    Returns:
        hidden_state: unpartitioned sequences with [batch_size, height, width, num_channels].
    """
    padded_height, padded_width = pad_height_width
    height, width = height_width
    batch_size = windows.shape[0] // (padded_height * padded_width // window_size // window_size)
    hidden_state = windows.view(
        batch_size, padded_height // window_size, padded_width // window_size, window_size, window_size, -1
    )
    hidden_state = hidden_state.permute(0, 1, 3, 2, 4, 5).contiguous()
    hidden_state = hidden_state.view(batch_size, padded_height, padded_width, -1)

    # We always have height <= padded_height and width <= padded_width
    hidden_state = hidden_state[:, :height, :width, :].contiguous()
    return hidden_state


class Sam3LiteTextViTLayer(GradientCheckpointingLayer):
    """Vision Transformer layer with rotary position embeddings and optional windowed attention."""

    def __init__(self, config: Sam3LiteTextViTConfig, window_size: int = 0) -> None:
        super().__init__()

        hidden_size = config.hidden_size
        image_size = config.image_size
        image_size = image_size if isinstance(image_size, (list, tuple)) else (image_size, image_size)

        patch_size = config.patch_size
        patch_size = patch_size if isinstance(patch_size, (list, tuple)) else (patch_size, patch_size)

        input_size = (image_size[0] // patch_size[0], image_size[1] // patch_size[1])
        self.layer_norm1 = nn.LayerNorm(hidden_size, eps=config.layer_norm_eps)
        rotary_input_size = input_size if window_size == 0 else (window_size, window_size)
        rotary_scale = config.window_size / rotary_input_size[0]
        self.rotary_emb = Sam3LiteTextViTRotaryEmbedding(
            config, end_x=rotary_input_size[0], end_y=rotary_input_size[1], scale=rotary_scale
        )
        self.attention = Sam3LiteTextViTRoPEAttention(config)
        self.layer_norm2 = nn.LayerNorm(hidden_size, eps=config.layer_norm_eps)
        self.mlp = Sam3LiteTextMLP(config)
        self.dropout = nn.Dropout(config.hidden_dropout)

        self.window_size = window_size

    def forward(
        self,
        hidden_states: torch.Tensor,
        **kwargs: Unpack[TransformersKwargs],
    ) -> torch.Tensor:
        residual = hidden_states

        hidden_states = self.layer_norm1(hidden_states)

        if self.window_size > 0:
            height, width = hidden_states.shape[1], hidden_states.shape[2]
            # Partition into non-overlapping windows for efficient attention
            hidden_states, pad_height_width = window_partition(hidden_states, self.window_size)

        position_embeddings = self.rotary_emb()
        hidden_states, _ = self.attention(hidden_states, position_embeddings, **kwargs)

        if self.window_size > 0:
            # Reverse window partition to restore original spatial layout
            hidden_states = window_unpartition(hidden_states, self.window_size, pad_height_width, (height, width))

        hidden_states = residual + hidden_states
        residual = hidden_states
        hidden_states = self.layer_norm2(hidden_states)
        hidden_states = self.mlp(hidden_states)
        hidden_states = residual + self.dropout(hidden_states)

        return hidden_states


@auto_docstring
class Sam3LiteTextViTModel(Sam3LiteTextPreTrainedModel):
    config: Sam3LiteTextViTConfig
    _can_record_outputs = {
        "hidden_states": Sam3LiteTextViTLayer,
        "attentions": Sam3LiteTextViTRoPEAttention,
    }

    def __init__(self, config: Sam3LiteTextViTConfig):
        super().__init__(config)
        self.config = config
        self.embeddings = Sam3LiteTextViTEmbeddings(config)
        self.layer_norm = nn.LayerNorm(config.hidden_size, eps=config.layer_norm_eps)
        self.layers = nn.ModuleList(
            [
                Sam3LiteTextViTLayer(
                    config, window_size=config.window_size if i not in config.global_attn_indexes else 0
                )
                for i in range(config.num_hidden_layers)
            ]
        )
        self.post_init()

    def get_input_embeddings(self) -> Sam3LiteTextViTPatchEmbeddings:
        return self.embeddings.patch_embeddings

    @merge_with_config_defaults
    @capture_outputs(tie_last_hidden_states=False)
    @auto_docstring
    def forward(
        self,
        pixel_values: torch.Tensor,
        **kwargs: Unpack[TransformersKwargs],
    ) -> BaseModelOutput:
        hidden_states = self.embeddings(pixel_values)  # [batch_size, seq_len, hidden_size]

        batch_size = hidden_states.shape[0]
        height = pixel_values.shape[-2] // self.config.patch_size
        width = pixel_values.shape[-1] // self.config.patch_size
        hidden_size = hidden_states.shape[-1]

        # Reshape to spatial format for windowed attention: [batch_size, height, width, hidden_size]
        hidden_states = hidden_states.view(batch_size, height, width, hidden_size)

        hidden_states = self.layer_norm(hidden_states)
        for layer in self.layers:
            hidden_states = layer(hidden_states, **kwargs)

        # Reshape back to sequence format: [batch_size, height*width, hidden_size]
        hidden_states = hidden_states.view(batch_size, height * width, hidden_size)

        return BaseModelOutput(last_hidden_state=hidden_states)


